const javaPrim = { string:'String', number:'Long', boolean:'Boolean', decimal:'java.math.BigDecimal', date:'java.time.LocalDateTime', uuid:'java.util.UUID' };
isPrim = function (t) { return Object.prototype.hasOwnProperty.call(javaPrim, t); };
javaShort = function (fq) { const dot = fq.lastIndexOf('.'); return dot >= 0 ? fq.slice(dot + 1) : fq; };
// reference: true → stored as the referent's UUID, not embedded. Map to UUID.
javaTypeOf = function (a) {
  if (a.reference && !isPrim(a.type)) return 'UUID';
  if (isPrim(a.type)) return javaShort(javaPrim[a.type]);
  return pascalCase(a.type);
};
fqOf = function (a) {
  if (a.reference && !isPrim(a.type)) return 'java.util.UUID';
  if (isPrim(a.type) && javaPrim[a.type].includes('.')) return javaPrim[a.type];
  return null;
};
fields = (attributes || []).map(function (a) { return { camel: camelCase(a.name), javaType: javaTypeOf(a), fq: fqOf(a) }; });
const importSet = new Set();
for (const f of fields) { if (f.fq) importSet.add(f.fq); }
importLines = Array.from(importSet).sort().map(function (i) { return 'import ' + i + ';'; }).join('\n');
pkgPath = ($packages && $packages.length ? $packages.map(function (p) { return p.name; }).join('.') : 'com.example.model');
recordParams = fields.map(function (f) { return '    ' + f.javaType + ' ' + f.camel; }).join(',\n');

